def lambda_handler(event, context):
    # Set up logging
    logger = logging.getLogger()
    logger.setLevel(logging.INFO)

    # Extract bucket and key from the Lambda event
    bucket_name = event['Records'][0]['s3']['bucket']['name']
    object_key = event['Records'][0]['s3']['object']['key']

    try:
        # Read image from S3
        response = s3_client.get_object(Bucket=bucket_name, Key=object_key)
        image_content = response['Body'].read()

        # Process the image (example: convert to grayscale)
        image = Image.open(io.BytesIO(image_content))
        gray_image = image.convert('L')
        output_buffer = io.BytesIO()
        gray_image.save(output_buffer, format='JPEG')

        # Write processed image back to S3
        output_key = f'processed/{object_key}'
        s3_client.put_object(Bucket=bucket_name, Key=output_key, Body=output_buffer.getvalue(), ContentType='image/jpeg')

        # Send notification via SNS
        sns_topic_arn = 'your-sns-topic-arn'
        message = {
            "bucket": bucket_name,
            "original_key": object_key,
            "processed_key": output_key
        }
        sns_client.publish(TopicArn=sns_topic_arn, Message=json.dumps(message))

        logger.info(f"Processed image {object_key} and stored as {output_key}")
        return {
            'statusCode': 200,
            'body': json.dumps('Image processed successfully')
        }

    except Exception as e:
        logger.error(f"Error processing image {object_key}: {str(e)}")
        return {
            'statusCode': 500,
            'body': json.dumps('Error processing image')
        }